import { useState } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleUpload = async () => {
    if (!file) return alert("Please select an image");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      const data = await response.json();
      setResult(data);
    } catch (error) {
      alert("Something went wrong!");
    }

    setLoading(false);
  };

  return (
    <div style={styles.page}>
      <div style={styles.wrapper}>
        <header style={styles.header}>
          <h1 style={styles.logo}>ClaimPilot</h1>
          <span style={styles.badge}>AI Damage Intelligence</span>
        </header>

        <div style={styles.uploadSection}>
          <h2 style={styles.heading}>
            Vehicle Damage Assessment
          </h2>
          <p style={styles.subheading}>
            Upload a damage image to generate repair estimate and fraud risk analysis.
          </p>

          <div style={styles.uploadBox}>
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setFile(e.target.files[0])}
              style={styles.fileInput}
            />
            <p style={{ color: "#666" }}>
              {file ? file.name : "Drag & drop or click to upload image"}
            </p>
          </div>

          <button
            onClick={handleUpload}
            disabled={loading}
            style={loading ? styles.buttonDisabled : styles.button}
          >
            {loading ? "Analyzing..." : "Generate AI Report"}
          </button>
        </div>

        {result && (
          <div style={styles.resultContainer}>
            <h3 style={styles.sectionTitle}>Audit Summary</h3>

            <div style={styles.statsGrid}>
              <div style={styles.stat}>
                <p>Total Estimate</p>
                <h4>PKR {result.total_estimate_pkr}</h4>
              </div>

              <div style={styles.stat}>
                <p>Fraud Confidence</p>
                <h4>{result.fraud_confidence_score}</h4>
              </div>

              <div style={styles.stat}>
                <p>Verdict</p>
                <h4>{result.verdict}</h4>
              </div>
            </div>

            <div style={styles.details}>
              <h4>Fraud Analysis</h4>
              <p>{result.fraud_analysis}</p>

              <h4>Damaged Parts</h4>
              <ul>
                {result.damaged_parts?.map((part, index) => (
                  <li key={index}>{part}</li>
                ))}
              </ul>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "#f8f9fb",
    padding: "40px 20px",
    display: "flex",
    justifyContent: "center",
  },

  wrapper: {
    width: "100%",
    maxWidth: "900px",
  },

  header: {
    marginBottom: "50px",
  },

  logo: {
    fontSize: "28px",
    fontWeight: "700",
    marginBottom: "6px",
  },

  badge: {
    fontSize: "14px",
    color: "#555",
  },

  uploadSection: {
    background: "white",
    padding: "40px",
    borderRadius: "16px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.05)",
    marginBottom: "40px",
  },

  heading: {
    marginBottom: "10px",
  },

  subheading: {
    color: "#666",
    marginBottom: "30px",
  },

  uploadBox: {
    border: "2px dashed #ddd",
    padding: "30px",
    borderRadius: "12px",
    textAlign: "center",
    marginBottom: "20px",
    cursor: "pointer",
  },

  fileInput: {
    marginBottom: "15px",
  },

  button: {
    width: "100%",
    padding: "14px",
    borderRadius: "10px",
    border: "none",
    background: "#111",
    color: "white",
    fontWeight: "600",
    cursor: "pointer",
  },

  buttonDisabled: {
    width: "100%",
    padding: "14px",
    borderRadius: "10px",
    border: "none",
    background: "#999",
    color: "white",
  },

  resultContainer: {
    background: "white",
    padding: "40px",
    borderRadius: "16px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.05)",
  },

  sectionTitle: {
    marginBottom: "20px",
  },

  statsGrid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
    gap: "20px",
    marginBottom: "30px",
  },

  stat: {
    background: "#f4f6f9",
    padding: "20px",
    borderRadius: "12px",
  },

  details: {
    lineHeight: "1.6",
  },
};

export default App;
